public class TimeUtils {

    private static final String YYYYMMMDDHHMMSS = "yyyy-MM-dd HH:mm:ss";

    public static Timestamp getCurrentTime() {
        return new Timestamp(System.currentTimeMillis());
    }

    public static String getCurrentTimeStr() {
        Calendar c = Calendar.getInstance();
        c.setTimeInMillis(System.currentTimeMillis());
        return DateFormatUtils.format(c.getTime(), YYYYMMMDDHHMMSS);
    }
}

public class PromptRequestParamExtractor extends AbstractRpcParamExtractor {

    private static final String PROMPT_DATA_ID_SUFFIX = ".json";

    @Override
    public List<ParamInfo> extractParam(Request request) throws NacosException {
        QueryPromptRequest promptRequest = (QueryPromptRequest) request;
        ParamInfo paramInfo = new ParamInfo();
        paramInfo.setNamespaceId(promptRequest.getNamespaceId());
        if (StringUtils.isNotBlank(promptRequest.getPromptKey())) {
            paramInfo.setDataId(promptRequest.getPromptKey() + PROMPT_DATA_ID_SUFFIX);
        }
        return List.of(paramInfo);
    }
}

public class ServiceQueryRequestParamExtractor extends AbstractRpcParamExtractor {

    @Override
    public List<ParamInfo> extractParam(Request request) {
        ServiceQueryRequest req = (ServiceQueryRequest) request;
        ParamInfo paramInfo = new ParamInfo();
        paramInfo.setNamespaceId(req.getNamespace());
        paramInfo.setServiceName(req.getServiceName());
        paramInfo.setGroup(req.getGroupName());
        paramInfo.setPort(String.valueOf(req.getUdpPort()));
        paramInfo.setClusters(req.getCluster());
        ArrayList<ParamInfo> paramInfos = new ArrayList<>();
        paramInfos.add(paramInfo);
        return paramInfos;
    }
}

